   617→  <script>
   618→    let mediaStream = null;
   619→    let mediaRecorder = null;
   620→    let recordedChunks = [];
   621→    let currentQuestionIndex = 0;
   622→    let questions = [];
   623→    let responses = [];
   624→    let interviewId = null;
   625→    let timerInterval = null;
