   964→    function updateTimer() {
   965→      const minutes = Math.floor(timeRemaining / 60);
   966→      const seconds = timeRemaining % 60;
   967→      const timerEl = document.getElementById('timer');
   968→
   969→      timerEl.textContent = `${minutes}:${seconds.toString().padStart(2, '0')}`;
   970→
   971→      if (timeRemaining <= 10) {
