let micLevelAnimationId = null;

// Initialize
document.addEventListener('DOMContentLoaded', async () => {
  const user = await checkAuth();
  if (!user) {
    window.location.href = '/login.html';
    return;
  }

  // Get interview ID from URL or create new
  const urlParams = new URLSearchParams(window.location.search);
  const jobId = urlParams.get('job_id');

  // Request camera AND microphone access
  try {
    mediaStream = await navigator.mediaDevices.getUserMedia({
      video: { width: 1280, height: 720 },
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }
    });
    document.getElementById('preview-video').srcObject = mediaStream;
    document.getElementById('preview-overlay').style.display = 'none';

    // Verify audio tracks are present and active
    const audioTracks = mediaStream.getAudioTracks();
    if (audioTracks.length === 0) {
      console.error('No audio tracks in stream');
      updateMicStatus('error', 'Microphone not detected');
    } else {
      const audioTrack = audioTracks[0];
      console.log('Audio track:', audioTrack.label, 'enabled:', audioTrack.enabled, 'muted:', audioTrack.muted);

      if (!audioTrack.enabled) {
        audioTrack.enabled = true;
      }

      updateMicStatus('active', `Mic: ${audioTrack.label || 'Active'}`);

      // Start audio level visualization
      startAudioLevelMeter(mediaStream);
    }

    // Initialize video analyzer
    videoAnalyzer = new VideoAnalyzer();
    const initialized = await videoAnalyzer.init();

    if (initialized) {
      console.log('Video analyzer ready');

      // Listen for live score updates
      videoAnalyzer.on('scores', (scores) => {
        updateLiveMetrics(scores);
      });
    } else {
      console.warn('Video analyzer initialization failed - continuing without analysis');
    }
  } catch (err) {
    console.error('Camera/microphone access error:', err);
    if (err.name === 'NotAllowedError') {
      alert('Camera and microphone access is required for video interviews. Please allow both permissions and reload the page.');
    } else if (err.name === 'NotFoundError') {
      alert('Camera or microphone not found. Please connect your devices and reload.');
    } else {
      alert('Failed to access camera and microphone: ' + err.message);
    }
    updateMicStatus('error', 'Microphone access denied');
  }
});

// Microphone status helpers
function updateMicStatus(status, label) {
  const micStatusEl = document.getElementById('mic-status');
  const micLabelEl = document.getElementById('mic-label');

  micStatusEl.className = 'mic-status ' + status;
  micLabelEl.textContent = label;
}

// Audio level meter using Web Audio API
function startAudioLevelMeter(stream) {
  try {
    audioContext = new (window.AudioContext || window.webkitAudioContext)();
    const source = audioContext.createMediaStreamSource(stream);
    audioAnalyser = audioContext.createAnalyser();
    audioAnalyser.fftSize = 256;
    audioAnalyser.smoothingTimeConstant = 0.8;
    source.connect(audioAnalyser);

    const dataArray = new Uint8Array(audioAnalyser.frequencyBinCount);

    function updateLevel() {
      if (!audioAnalyser) return;

      audioAnalyser.getByteFrequencyData(dataArray);

      // Calculate average level
      let sum = 0;
