// Microphone status helpers
function updateMicStatus(status, label) {
  const micStatusEl = document.getElementById('mic-status');
  const micLabelEl = document.getElementById('mic-label');

  micStatusEl.className = 'mic-status ' + status;
  micLabelEl.textContent = label;
}

// Audio level meter using Web Audio API
function startAudioLevelMeter(stream) {
  try {
    audioContext = new (window.AudioContext || window.webkitAudioContext)();
    const source = audioContext.createMediaStreamSource(stream);
    audioAnalyser = audioContext.createAnalyser();
    audioAnalyser.fftSize = 256;
    audioAnalyser.smoothingTimeConstant = 0.8;
    source.connect(audioAnalyser);

    const dataArray = new Uint8Array(audioAnalyser.frequencyBinCount);

    function updateLevel() {
      if (!audioAnalyser) return;

      audioAnalyser.getByteFrequencyData(dataArray);

      // Calculate average level
      let sum = 0;
      for (let i = 0; i < dataArray.length; i++) {
        sum += dataArray[i];
      }
      const avg = sum / dataArray.length;
      const level = Math.min(100, (avg / 128) * 100);

      // Update both mic level bars
      const previewFill = document.getElementById('mic-level-fill');
      const recordingFill = document.getElementById('recording-mic-level');

      if (previewFill) previewFill.style.width = level + '%';
      if (recordingFill) recordingFill.style.width = level + '%';

      micLevelAnimationId = requestAnimationFrame(updateLevel);
    }

    updateLevel();
  } catch (err) {
    console.warn('Audio level meter not available:', err);
  }
}

